import{_ as o,o as t,c as a,ae as r}from"./chunks/framework.CyZiF_rV.js";const c="/ksef-docs/assets/hwm.CnKORmUR.png",d="/ksef-docs/assets/hwm-1.Bdx9PjiU.png",i="/ksef-docs/assets/hwm-2.CZj0KUSn.png",M=JSON.parse('{"title":"High Water Mark (HWM)","description":"","frontmatter":{},"headers":[],"relativePath":"ru/pobieranie-faktur/hwm.md","filePath":"ru/pobieranie-faktur/hwm.md"}'),l={name:"ru/pobieranie-faktur/hwm.md"};function n(s,e,p,u,h,m){return t(),a("div",null,[...e[0]||(e[0]=[r('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/pobieranie-faktur/hwm.md" target="_blank" rel="noreferrer">pobieranie-faktur/hwm.md</a></p></blockquote><h1 id="high-water-mark-hwm" tabindex="-1">High Water Mark (HWM) <a class="header-anchor" href="#high-water-mark-hwm" aria-label="Permalink to &quot;High Water Mark (HWM)&quot;">​</a></h1><p>25.11.2025</p><p>Механизм High Water Mark (HWM) описывает, как KSeF управляет полнотой данных во времени для даты <code>PermanentStorage</code>.</p><p>В каждый момент времени система знает момент времени (<code>HWM</code>), до которого она уже имеет уверенность, что все счета-фактуры были записаны и не появятся новые документы с датой <code>PermanentStorage</code> более ранней или равной этому моменту.</p><p><img src="'+c+'" alt="HWM"></p><ul><li>Для времени ≤ <code>HWM</code> - все счета-фактуры с датой <code>PermanentStorage</code> в этом промежутке уже были постоянно записаны в KSeF. Система гарантирует, что в будущем уже не появится ни одна новая счет-фактура с датой <code>PermanentStorage</code> ≤ <code>HWM</code>.</li><li>В промежутке (<code>HWM</code>, <code>Сейчас</code>): <ul><li>часть счетов-фактур уже видна и может быть возвращена в запросе,</li><li>ввиду асинхронного и многопоточного характера процесса записи, в этом промежутке могут еще появиться новые счета-фактуры, т.е. с датой <code>PermanentStorage</code>, находящейся в диапазоне (<code>HWM</code>, <code>Сейчас</code>].</li></ul></li></ul><p>Вывод:</p><ul><li>все, что ≤ <code>HWM</code>, можно рассматривать как <strong>закрытый</strong> и <strong>полный</strong> набор,</li><li>все, что &gt; <code>HWM</code>, является <strong>потенциально неполным</strong> и требует осторожного обращения при синхронизации.</li></ul><h2 id="сценарии-1-синхронизация-только-до-hwm" tabindex="-1">Сценарий 1 - синхронизация &quot;только до HWM&quot; <a class="header-anchor" href="#сценарии-1-синхронизация-только-до-hwm" aria-label="Permalink to &quot;Сценарий 1 - синхронизация &quot;только до HWM&quot;&quot;">​</a></h2><p><img src="'+d+'" alt="HWM-1"></p><p>Система при каждом запросе получает счета-фактуры <strong>от &quot;последней известной точки&quot; только до текущего значения <code>HWM</code></strong>. Новое значение <code>HWM</code> становится началом следующего промежутка.</p><p>Преимущества:</p><ul><li>данные до <code>HWM</code> являются окончательными - не нужно повторно проверять тот же промежуток,</li><li>количество дубликатов между последовательными получениями минимально.</li></ul><p>Последствия:</p><ul><li>часть самых свежих счетов-фактур из диапазона <code>(HWM, Сейчас]</code> не видна в локальной системе - появится только после смещения <code>HWM</code> в следующем цикле.</li></ul><p>Этот сценарий рекомендуется для инкрементальной, автоматической синхронизации данных, в которых оптимизация трафика и минимизация количества дубликатов важнее немедленной доступности самых свежих счетов-фактур.</p><h2 id="сценарии-2-синхронизация-до-сеичас" tabindex="-1">Сценарий 2 - синхронизация &quot;до Сейчас&quot; <a class="header-anchor" href="#сценарии-2-синхронизация-до-сеичас" aria-label="Permalink to &quot;Сценарий 2 - синхронизация &quot;до Сейчас&quot;&quot;">​</a></h2><p><img src="'+i+'" alt="HWM-2"></p><p>Система, интегрирующаяся с KSeF, выполняет циклические, инкрементальные запросы <strong>от последней начальной точки до <code>Сейчас</code></strong> и записывает все возвращенные счета-фактуры, также из промежутка <code>(HWM, Сейчас]</code>.</p><p>Поскольку данные в этом промежутке могут быть неполными, <strong>следующий запрос повторяет часть диапазона</strong> - как минимум от предыдущего <code>HWM</code> до нового <code>Сейчас</code>. Со стороны локальной системы необходима дедупликация (например, по номеру KSeF).</p><p>Преимущества:</p><ul><li>локальная система (и пользователь) видит новейшие счета-фактуры как можно быстрее, не дожидаясь, пока <code>HWM</code> их &quot;догонит&quot;.</li></ul><p>Последствия:</p><ul><li>диапазон <code>(HWM, Сейчас]</code> должен быть проверен повторно при следующем запросе,</li><li>появятся дубликаты, которые следует удалять со стороны локальной системы.</li></ul><p>Тот же механизм может использоваться также <strong>ad hoc</strong>, когда пользователь вручную требует обновления данных - система получает тогда &quot;здесь и сейчас&quot; самые свежие доступные счета-фактуры от последней известной даты до <code>Сейчас</code>.</p><h2 id="связанные-документы" tabindex="-1">Связанные документы <a class="header-anchor" href="#связанные-документы" aria-label="Permalink to &quot;Связанные документы&quot;">​</a></h2><ul><li><a href="./przyrostowe-pobieranie-faktur.html">Инкрементальное получение счетов-фактур</a></li></ul>',28)])])}const H=o(l,[["render",n]]);export{M as __pageData,H as default};
